package DailyAssignments;

public class Assgnmt1_ASCII_23_06_2026 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		/*
		 * Assignment 1: ASCII Code Program Question: Write a Java program to print the
		 * ASCII value of the following characters:
		 *  A
		 *  a
		 *  0
		 *	@
		 * Expected Output: ASCII value of A = 65; ASCII value of a = 97; ASCII value of 0 = 48; ASCII value of @ = 64
		 */
		
		char val1 = 'A'; char val2 = 'a'; char val3 = '0'; char val4 = '@';
		int asc1 = val1; int asc2 = val2; int asc3 = val3; int asc4 = val4;
		System.out.println("ASCII for A:"+ asc1);
		System.out.println("ASCII for a:"+ asc2);
		System.out.println("ASCII for 0:"+ asc3);
		System.out.println("ASCII for @:"+ asc4);
	}

}
